import{_ as a,o,c as t,ag as i}from"./chunks/framework.CanvC6-R.js";const h=JSON.parse('{"title":"Summary","description":"","frontmatter":{},"headers":[],"relativePath":"language/summary.md","filePath":"language/summary.md"}'),l={name:"language/summary.md"};function r(s,e,n,c,d,u){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h1><p>This page provides a concise reference of everything covered in this documentation.</p><h2 id="project-structure" tabindex="-1">Project Structure <a class="header-anchor" href="#project-structure" aria-label="Permalink to &quot;Project Structure&quot;">​</a></h2><p>Every Bliss project requires two components:</p><ul><li><code>bliss.toml</code> — marks the project root</li><li><code>src/main.bls</code> — the sole entry point of every Bliss program</li></ul><h2 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core Concepts&quot;">​</a></h2><h3 id="expressions-and-statements" tabindex="-1">Expressions and Statements <a class="header-anchor" href="#expressions-and-statements" aria-label="Permalink to &quot;Expressions and Statements&quot;">​</a></h3><ul><li>An <strong>expression</strong> produces a value: literals, identifiers, binary expressions, unary expressions, function calls, and data initialization.</li><li>A <strong>statement</strong> performs an action but produces no value: variable declarations, reassignment, function definitions, control flow, blocks, <code>import</code>, and <code>use</code>.</li><li>Assignment is always a statement. A function call is always an expression.</li></ul><h3 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h3><ul><li>Bliss is statically typed. All types are explicitly declared. There are no implicit conversions.</li><li><strong>Scalar types:</strong> <code>i8</code>, <code>i16</code>, <code>i32</code>, <code>i64</code>, <code>u8</code>, <code>u16</code>, <code>u32</code>, <code>u64</code>, <code>f32</code>, <code>f64</code>, <code>bool</code>, <code>void</code></li><li><strong>Composite types:</strong> arrays (<code>Type[]</code>, <code>Type[size]</code>) and <code>data</code></li><li><strong>Strings</strong> are <code>u8[]</code> — string literals are syntactic sugar for character arrays.</li></ul><h2 id="language-reference" tabindex="-1">Language Reference <a class="header-anchor" href="#language-reference" aria-label="Permalink to &quot;Language Reference&quot;">​</a></h2><h3 id="variables" tabindex="-1">Variables <a class="header-anchor" href="#variables" aria-label="Permalink to &quot;Variables&quot;">​</a></h3><ul><li>Declared with <code>let &lt;name&gt;: &lt;Type&gt;</code> — type annotation is always required.</li><li>Initialization is optional: <code>let x: i32 = 5</code> or <code>let x: i32</code>.</li><li>Reassignment is valid: <code>x = 10</code>.</li><li>Compound operators (<code>+=</code>, <code>-=</code>) are not valid.</li><li>Array elements are assigned with <code>arr[index] = value</code> — out-of-bounds is an unrecoverable error.</li></ul><h3 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h3><ul><li>Defined with <code>fx &lt;name&gt;( &lt;args&gt; ) -&gt; &lt;ReturnType&gt; { }</code> — return type is optional.</li><li>Arguments are written as <code>&lt;name&gt;: &lt;type&gt;</code> pairs.</li><li>A function definition is a statement. A function call is always an expression.</li><li><strong>Primitives</strong> are passed by value. <strong>Arrays and data types</strong> are passed by reference.</li><li><code>copy</code> in the argument definition copies the entity into the function&#39;s stack frame.</li><li><code>copy</code> at the call site allocates a heap copy and passes a pointer to it.</li><li>Taking a reference of a primitive is not permitted.</li></ul><h3 id="control-flow" tabindex="-1">Control Flow <a class="header-anchor" href="#control-flow" aria-label="Permalink to &quot;Control Flow&quot;">​</a></h3><ul><li>All control flow constructs are statements.</li><li>Conditions must be boolean expressions that evaluate to <code>bool</code>.</li><li><code>if</code> can stand alone. <code>elif</code> and <code>else</code> must be preceded by <code>if</code>.</li><li><code>while</code> is the only loop construct. The body executes as long as the condition is <code>true</code>.</li></ul><h3 id="data" tabindex="-1">Data <a class="header-anchor" href="#data" aria-label="Permalink to &quot;Data&quot;">​</a></h3><ul><li>Defined with <code>data &lt;Name&gt; { &lt;field&gt;: &lt;Type&gt;, ... }</code>.</li><li>All fields must be initialized: <code>DataType { field = value, ... }</code>.</li><li><code>data</code> types are always passed by reference.</li></ul><h3 id="arrays" tabindex="-1">Arrays <a class="header-anchor" href="#arrays" aria-label="Permalink to &quot;Arrays&quot;">​</a></h3><ul><li>Fixed in size — cannot be resized once created.</li><li>Declared as <code>Type[]</code> (with values) or <code>Type[size]</code> (pre-defined size).</li><li>Always passed by reference.</li><li>Out-of-bounds assignment is an unrecoverable error.</li></ul><h3 id="directives" tabindex="-1">Directives <a class="header-anchor" href="#directives" aria-label="Permalink to &quot;Directives&quot;">​</a></h3><ul><li><code>alias &lt;Type&gt; as &lt;Name&gt;</code> — masks a type under a new name. Compile-time only.</li><li><code>sub &lt;name&gt; = &lt;expr&gt;</code> — binds a name to an expression. Compile-time only.</li><li>Neither <code>alias</code> nor <code>sub</code> produces a runtime value or can be reassigned.</li></ul><h2 id="module-system" tabindex="-1">Module System <a class="header-anchor" href="#module-system" aria-label="Permalink to &quot;Module System&quot;">​</a></h2><h3 id="import" tabindex="-1">Import <a class="header-anchor" href="#import" aria-label="Permalink to &quot;Import&quot;">​</a></h3><ul><li><code>import &lt;package&gt;</code> — brings an external package into scope.</li><li><code>import &lt;package&gt;.&lt;module&gt;</code> — brings a specific module into scope.</li><li>The last segment of the path is what enters scope.</li></ul><h3 id="use" tabindex="-1">Use <a class="header-anchor" href="#use" aria-label="Permalink to &quot;Use&quot;">​</a></h3><ul><li><code>use &lt;path.to.file&gt;</code> — brings an internal project file into scope.</li><li>Paths are always resolved from the project root (<code>bliss.toml</code>), never relative.</li><li>The last segment of the path is what enters scope.</li><li>Only <code>pub</code> declarations are accessible from other files.</li></ul>',28)])])}const m=a(l,[["render",r]]);export{h as __pageData,m as default};
